type Meta struct {
	Title       string
	Description string
	URL         string
	Type        string
	Image       string
}

func SiteMeta(site config.Site) Meta {
	return Meta{
		Title:       site.Name,
		Description: site.Description,
		URL:         site.URL("/"),
		Type:        "website",
	}
}

func PostMeta(site config.Site, post posts.Post) Meta {
	urlPath := "/posts/" + post.Slug
	if post.Kind == "page" {
		urlPath = "/" + post.Slug
	}

	return Meta{
		Title:       post.Title,
		Description: post.Description,
		URL:         site.URL(urlPath),
		Type:        "article",
	}
}

func NotFoundMeta(site config.Site) Meta {
	return Meta{
		Title:       "Page not found",
		Description: "The requested page could not be found.",
		URL:         site.URL("/404"),
		Type:        "website",
		Image:       site.URL("/static/images/404.png"),
	}
}

